mapper.select:
SELECT DATE_FORMAT(create_time, '%Y-%m-%d') AS date, COUNT(*) AS count, department, doctor_id AS doctorId, doctor_name AS doctorName, IFNULL(SUM(total_amount), 0) AS totalAmount FROM outpatient_record WHERE deleted = 0
AND DATE(create_time) >= #{startDate}
AND DATE(create_time) <= #{endDate}
AND department = #{department}
AND doctor_id = #{doctorId}
GROUP BY date, department, doctor_id, doctor_name ORDER BY date DESC
